def gen(rng, size):
    k = max(1, min(size, 8))
    heights = [rng.randint(1, 4) for _ in range(k)]
    widths = [rng.randint(1, 4) for _ in range(k)]
    is_farm = [[rng.random() < 0.55 for _ in range(k)] for _ in range(k)]
    grid = []
    for bi in range(k):
        block_rows = [[] for _ in range(heights[bi])]
        for bj in range(k):
            fill = 1 if is_farm[bi][bj] else 0
            for r in range(heights[bi]):
                block_rows[r].extend([fill] * widths[bj])
            if bj < k - 1:
                for r in range(heights[bi]):
                    block_rows[r].append(0)
        grid.extend(block_rows)
        if bi < k - 1:
            sep_len = sum(widths) + (k - 1)
            grid.append([0] * sep_len)
    return [grid]

