class Solution:
    def findFarmland(self, land):
        rows = len(land)
        cols = len(land[0])
        visited = [[False] * cols for _ in range(rows)]
        res = []
        for r in range(rows):
            for c in range(cols):
                if land[r][c] == 1 and not visited[r][c]:
                    stack = [(r, c)]
                    visited[r][c] = True
                    minr = maxr = r
                    minc = maxc = c
                    while stack:
                        cr, cc = stack.pop()
                        minr = min(minr, cr)
                        maxr = max(maxr, cr)
                        minc = min(minc, cc)
                        maxc = max(maxc, cc)
                        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nr, nc = cr + dr, cc + dc
                            if 0 <= nr < rows and 0 <= nc < cols and land[nr][nc] == 1 and not visited[nr][nc]:
                                visited[nr][nc] = True
                                stack.append((nr, nc))
                    res.append([minr, minc, maxr, maxc])
        return res

