class Solution:
    def findFarmland(self, land):
        rows = len(land)
        cols = len(land[0])
        res = []
        for r in range(rows):
            for c in range(cols):
                if land[r][c] == 1 and (r == 0 or land[r - 1][c] == 0) and (c == 0 or land[r][c - 1] == 0):
                    r2 = r
                    while r2 + 1 < rows and land[r2 + 1][c] == 1:
                        r2 += 1
                    c2 = c
                    while c2 + 1 < cols and land[r][c2 + 1] == 1:
                        c2 += 1
                    res.append([r, c, r2, c2])
        return res

