var findFarmland = function(land) {
    const rows = land.length, cols = land[0].length;
    const res = [];
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            if (land[r][c] === 1 && (r === 0 || land[r - 1][c] === 0) && (c === 0 || land[r][c - 1] === 0)) {
                let r2 = r;
                while (r2 + 1 < rows && land[r2 + 1][c] === 1) r2++;
                let c2 = c;
                while (c2 + 1 < cols && land[r][c2 + 1] === 1) c2++;
                res.push([r, c, r2, c2]);
            }
        }
    }
    return res;
};
